import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;

public class Stocks {
	static class Task {
		int n,b,l;
		int[] costCurrent;
		int[] costMin;
		int[] costMax;
		private void readInput() {
			try {
				BufferedReader input = new BufferedReader(new FileReader("stocks.in"));
				String[] firstLine = input.readLine().split(" ");
				n = Integer.parseInt(firstLine[0]);
				b = Integer.parseInt(firstLine[1]);
				l = Integer.parseInt(firstLine[2]);
				costCurrent = new int[n + 1];
				costMin = new int[n + 1];
				costMax = new int[n + 1];
				for (int i = 1; i <= n; i++) {
					String[] line = input.readLine().split(" ");
					costCurrent[i] = Integer.parseInt(line[0]);
					costMin[i] = Integer.parseInt(line[1]);
					costMax[i] = Integer.parseInt(line[2]);
				}
				input.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}
		private int getResult() {
			ArrayList<Integer> luate = new ArrayList<>();
			int[][][] dp = new int[n + 1][l + 1][b + 1];
			//nu selectez nicio actiune
			for (int lim = 0; lim <= l; lim++) {
				for (int plati = 0; plati <= b; plati++) {
					dp[0][lim][plati] = 0;
				}
			}
			//lim este cat ar pierde in cel mai rau caz
			//plati este cat plateste
			//dp[i][lim][plati] = este profitul maxim obtinut din elementele i
			//cu o pierdere de maxim "lim" si cu investitie de maxim "plati" 
			for (int i = 1; i <= n; i++) {
				for (int lim = 0; lim <= l; lim++) {
					for (int plati = 0; plati <= b; plati++) {
						dp[i][lim][plati] = dp[i - 1][lim][plati];
						if ((lim - (costCurrent[i] - costMin[i]) >= 0)
							&& (plati - costCurrent[i]) >= 0) {
							int limitLoss = lim - (costCurrent[i] - costMin[i]);
							int inBuget = plati - costCurrent[i];
							int takeCost = dp[i - 1][limitLoss][inBuget]
								+ (costMax[i] - costCurrent[i]);
							dp[i][lim][plati] = Math.max(takeCost,dp[i - 1][lim][plati]);
						}
					}
				}
			}
			return dp[n][l][b];
		}
		public void afisare(int [][] m) {
			for (int i = 0; i <= n; i++) {
				for (int lim = 0; lim <= l; lim++) {
					System.out.print(m[i][lim] + " ");
				}
				System.out.println();
			}

		}
		public void output(int profit) {
			try {
				PrintWriter out = new PrintWriter(new File("stocks.out"));
				out.printf("%d", profit);
				out.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}
		public void solve() {
			readInput();
			int rez = getResult();
			output(rez);

		}
	}

	public static void main(String[] args) {
		new Stocks.Task().solve();
	}
}

#include <bits/stdc++.h>
using namespace std;

int dp[101][501][101];   // dp[N][B][K]

int main() {
	ifstream fin("stocks.in");
	ofstream fout("stocks.out");

	int N, B, L, tmp;
	vector<int> min, max, current;

	fin >> N >> B >> L;

	// cazuri de baza pentru dinamica
	for(int j = 0; j <= B; j++) {
		for(int k = 0; k <= L; k++) {
				dp[0][j][k] = 0;
		}
	}

	// elemente fictive, ca sa fie indexarea de la 1
	current.push_back(0);
	min.push_back(0);
	max.push_back(0);

	// citire
	for(int x, y, z, i = 0; i <= N; i++) {
		fin >> x >> y >> z;
		current.push_back(x);
		min.push_back(x - y);
		max.push_back(z - x);

		// cazuri de baza pentru dinamica
		for(int k = 0; k <= L; k++)
			dp[i][0][k] = 0;

		for(int j = 0; j <= B; j++)
			dp[i][j][0] = 0;
	}


	for(int i = 1; i <= N; i++) {
		for(int j = 0; j <= B; j++) {
			for(int k = 0; k <= L; k++) {
				// dp[i][j][k] e minimul dintre:
				// dp[i-1][j][k]
				// dp[i-1][j-current[i]][k - min[i]] + max[i]
				dp[i][j][k] = dp[i - 1][j][k];

				// trebuie mai intai sa verificam daca j-current[i] >= 0
				// si k - min[i] >= 0 ca sa fie indexi ptr vector
				if(current[i] <= j && min[i] <= k) {
					tmp = dp[i - 1][j-current[i]][k - min[i]] + max[i];
					if(tmp > dp[i][j][k])
						dp[i][j][k] = tmp;
				}
			}
		}
	}


	fout << dp[N][B][L];

	fout.close();
	fin.close();

	return 0;
}
